
/**
 * This object stores npc job types available to all scripting handlers through the "Job" keyword.
 */
declare namespace Job {
	var NONE: number;
	var BARD: number;
	var HEALER: number;
	var GUARD: number;
	var ITEM_GIVER: number;
	var FOLLOWER: number;
	var SPAWNER: number;
	var CONVERSATION: number;
	var CHUNK_LOADER: number;
}

